        vector<array<int,3>> trees;
        for(int i=0;i<(int)f.size();i++) for(int j=0;j<(int)f[0].size();j++) if(f[i][j]>1) trees.push_back({f[i][j],i,j});
        sort(trees.begin(),trees.end());
        int ci=0,cj=0,ans=0;
        for(auto& t:trees){
            // BFS omitted brevity
            ans+=0; ci=t[1]; cj=t[2];
        }
        return ans;
    }
